import React, { useState, useEffect, useRef, useLayoutEffect, useMemo } from 'react';
import { NovelChunk, SettingItem, KnowledgeItem, AiSettings } from '../types';
import { parseMarkdown } from '../utils';
import * as Icons from '../icons';
import { useStore } from '../store/index';

interface EditableParagraphProps {
    chunk: NovelChunk;
    characters: SettingItem[];
    knowledgeBase: KnowledgeItem[];
    onTextChange: (chunkId: string, newText: string) => void;
    onTogglePin: (chunkId: string) => void;
    isHighlighted: boolean;
    isEditing: boolean;
    onStartEdit: () => void;
    onEndEdit: () => void;
    scrollContainerRef: React.RefObject<HTMLDivElement>;
}

export const EditableParagraph: React.FC<EditableParagraphProps> = ({
    chunk, characters, knowledgeBase, onTextChange, onTogglePin, isHighlighted, isEditing, onStartEdit, onEndEdit, scrollContainerRef
}) => {
    const [editText, setEditText] = useState(chunk.text);
    const [brushColor, setBrushColor] = useState('#ff0000');
    const [isColorPaletteOpen, setIsColorPaletteOpen] = useState(false); // パレット開閉用
    const textareaRef = useRef<HTMLTextAreaElement>(null);
    const wrapperRef = useRef<HTMLDivElement>(null);
    const aiSettings = useStore(state => state.allProjectsData[state.activeProjectId]?.aiSettings);

    const isMac = useMemo(() => navigator.platform.toUpperCase().indexOf('MAC') >= 0, []);
    const modifierKeyText = isMac ? '⌘Cmd' : 'Ctrl';

    const scrollCorrectionData = useRef<{ top: number } | null>(null);
    const [isAwaitingCorrection, setIsAwaitingCorrection] = useState(false);

    useEffect(() => {
        if (isEditing) {
            setEditText(chunk.text);
            setTimeout(() => {
                if (textareaRef.current) {
                    textareaRef.current.focus({ preventScroll: true });
                    textareaRef.current.style.height = 'auto';
                    textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`;
                }
            }, 0);
        } else {
            setIsColorPaletteOpen(false); // 編集終了時に閉じる
        }
    }, [isEditing, chunk.text]);

    useEffect(() => {
        if (isHighlighted && wrapperRef.current) {
            wrapperRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
    }, [isHighlighted]);

    const measureAndStorePosition = () => {
        const container = scrollContainerRef.current;
        if (container && wrapperRef.current) {
            const containerRect = container.getBoundingClientRect();
            const elementRect = wrapperRef.current.getBoundingClientRect();
            const top = elementRect.top - containerRect.top;
            scrollCorrectionData.current = { top };
        }
    };

    useLayoutEffect(() => {
        if (isAwaitingCorrection && scrollCorrectionData.current !== null) {
            const container = scrollContainerRef.current;

            if (container && wrapperRef.current) {
                const containerRect = container.getBoundingClientRect();
                const newRect = wrapperRef.current.getBoundingClientRect();
                const newTop = newRect.top - containerRect.top;
                const oldTop = scrollCorrectionData.current.top;
                const delta = newTop - oldTop;

                if (Math.abs(delta) > 1) {
                    container.scrollTop += delta;
                }
            }
            scrollCorrectionData.current = null;
            setIsAwaitingCorrection(false);
        }
    }, [isAwaitingCorrection, chunk.text]);

    const handleSave = () => {
        measureAndStorePosition();
        setIsAwaitingCorrection(true);
        onTextChange(chunk.id, editText);
        onEndEdit();
    };

    const handleCancel = () => {
        measureAndStorePosition();
        setIsAwaitingCorrection(true);
        onEndEdit();
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
        if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) { e.preventDefault(); handleSave(); }
        if (e.key === 'Escape') { e.preventDefault(); handleCancel(); }
        if ((e.ctrlKey || e.metaKey)) {
            switch (e.key) {
                case 'b': e.preventDefault(); applyMarkdown('**'); break;
                case 'u': e.preventDefault(); applyMarkdown('__'); break;
                case 'h': e.preventDefault(); applyMarkdown('# '); break;
                case 'r': e.preventDefault(); applyMarkdown('{', '|かんじ}'); break;
                case 'c': if(e.shiftKey) { e.preventDefault(); applyMarkdown(`<c:${brushColor}>`, '</c>'); } break;
                default: break;
            }
        }
    };

    const applyMarkdown = (prefix: string, suffix: string = prefix, placeholder: string = 'テキスト') => {
        if (!textareaRef.current) return;
        const start = textareaRef.current.selectionStart;
        const end = textareaRef.current.selectionEnd;
        const selectedText = editText.substring(start, end);
        const newText = selectedText || placeholder;
        const replacement = `${prefix}${newText}${suffix}`;
        const newEditText = editText.substring(0, start) + replacement + editText.substring(end);
        setEditText(newEditText);

        setTimeout(() => {
            textareaRef.current?.focus({ preventScroll: true });
            if (selectedText) {
                textareaRef.current?.setSelectionRange(start + prefix.length, end + prefix.length);
            } else {
                textareaRef.current?.setSelectionRange(start + prefix.length, start + prefix.length + placeholder.length);
            }
        }, 0);
    };

    const wrapperClassName = `relative group transition-all duration-300 ${isHighlighted ? 'bg-indigo-500/10' : ''} ${chunk.isPinned ? 'bg-yellow-500/10' : ''} rounded-md my-4`;

    return (
        <div ref={wrapperRef} id={`chunk-${chunk.id}`} className={wrapperClassName}>
            {isEditing ? (
                <div className="bg-gray-800 border-2 border-indigo-500 rounded-md flex flex-col">
                    <div className="sticky-toolbar bg-gray-700">
                         <div className="p-2 flex gap-2 border-b border-gray-600 items-center">
                            <button title={`太字 (${modifierKeyText}+B)`} onClick={() => applyMarkdown('**')} className="p-1.5 text-white hover:bg-gray-600 rounded"><Icons.BoldIcon className="h-4 w-4" /></button>
                            <button title={`下線 (${modifierKeyText}+U)`} onClick={() => applyMarkdown('__')} className="p-1.5 text-white hover:bg-gray-600 rounded"><Icons.UnderlineIcon className="h-4 w-4" /></button>
                            <button title={`見出し (${modifierKeyText}+H)`} onClick={() => applyMarkdown('# ')} className="p-1.5 text-white hover:bg-gray-600 rounded"><Icons.TypeIcon className="h-4 w-4" /></button>
                            <button title={`ルビ (${modifierKeyText}+R)`} onClick={() => applyMarkdown('{', '|かんじ}')} className="p-1.5 text-white hover:bg-gray-600 rounded font-bold text-xs">ルビ</button>

                            {/* カラーパレットUIのラップ */}
                            <div className="relative flex items-center">
                                <div className="flex items-center gap-1 ml-1 bg-gray-800/50 rounded pr-1">
                                    <button 
                                        title={`文字色を適用 (${modifierKeyText}+Shift+C)`} 
                                        onClick={() => applyMarkdown(`<c:${brushColor}>`, '</c>')} 
                                        className="p-1.5 text-white hover:bg-gray-600 rounded" 
                                        style={{ color: brushColor }}
                                    >
                                        <Icons.PaletteIcon className="h-4 w-4" />
                                    </button>
                                    <button 
                                        onClick={() => setIsColorPaletteOpen(!isColorPaletteOpen)}
                                        className="p-0.5 text-gray-400 hover:text-white transition-colors"
                                        title="色を選択"
                                    >
                                        <Icons.ChevronDownIcon className={`h-3 w-3 transition-transform ${isColorPaletteOpen ? 'rotate-180' : ''}`} />
                                    </button>
                                </div>

                                {/* パレットポップオーバー（STEP1: 仮実装） */}
                                {isColorPaletteOpen && (
                                    <div className="absolute top-full left-1 mt-2 z-50 bg-gray-800 border border-gray-600 rounded shadow-2xl p-3 min-w-[120px] animate-in fade-in zoom-in duration-150">
                                        <div className="text-xs font-bold text-gray-400 mb-2 border-b border-gray-700 pb-1">Color Palette</div>
                                        <div className="flex items-center gap-2">
                                            <input 
                                                type="color" 
                                                value={brushColor} 
                                                onChange={(e) => setBrushColor(e.target.value)} 
                                                className="w-6 h-6 bg-transparent border-none cursor-pointer p-0"
                                            />
                                            <span className="text-xs text-white font-mono">{brushColor.toUpperCase()}</span>
                                        </div>
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                    <div className="relative">
                        <textarea
                            ref={textareaRef}
                            value={editText}
                            onChange={(e) => {
                                setEditText(e.target.value);
                                e.target.style.height = 'auto';
                                e.target.style.height = `${textareaRef.current.scrollHeight}px`;
                            }}
                            onKeyDown={handleKeyDown}
                            className="w-full bg-transparent p-2 text-white focus:outline-none resize-y"
                            aria-label="本文段落の編集"
                            style={{
                                minHeight: '100px',
                                fontFamily: 'inherit',
                                fontSize: 'inherit',
                                lineHeight: 'inherit',
                                overflowY: 'auto',
                            }}
                        />
                    </div>
                     <div className="mt-2 flex justify-end gap-2 p-2">
                        <button onClick={handleCancel} className="flex items-center gap-1 px-3 py-1 bg-gray-600 text-white text-xs rounded hover:bg-gray-500">
                            <Icons.XIcon className="h-3 w-3" />
                            キャンセル
                        </button>
                        <button onClick={handleSave} className="flex items-center gap-1 px-3 py-1 bg-indigo-600 text-white text-xs rounded hover:bg-indigo-500">
                            <Icons.CheckIcon className="h-3 w-3" />
                            保存 ({modifierKeyText}+Enter)
                        </button>
                    </div>
                </div>
            ) : (
                <>
                    {chunk.isPinned && <Icons.PinIcon aria-hidden="true" className="absolute top-1 left-1 h-3 w-3 text-yellow-400 fill-current" title="この段落はピン留めされています" />}
                    <div className={`whitespace-pre-wrap ${chunk.isPinned ? 'pl-5' : ''}`} dangerouslySetInnerHTML={{ __html: parseMarkdown(chunk.text, characters, knowledgeBase, aiSettings) || '<br/>' }} />
                    <div className="absolute -top-2 -right-2 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity focus-within:opacity-100">
                        <button 
                            onClick={() => onTogglePin(chunk.id)} 
                            title={chunk.isPinned ? "ピンを外す" : "ピン留めする"} 
                            aria-label={chunk.isPinned ? "この段落のピン留めを外す" : "この段落をピン留めする"}
                            aria-pressed={chunk.isPinned}
                            className={`p-1.5 bg-gray-700 text-gray-300 rounded-full focus:opacity-100 ${chunk.isPinned ? 'text-yellow-400' : 'hover:text-yellow-400'}`}
                        >
                           <Icons.PinIcon aria-hidden="true" className={`h-4 w-4 ${chunk.isPinned ? 'fill-current' : ''}`} />
                        </button>
                        <button 
                            onClick={onStartEdit} 
                            title="編集" 
                            aria-label="この段落を編集する"
                            className="p-1.5 bg-gray-700 text-gray-300 rounded-full focus:opacity-100 hover:text-white"
                        >
                            <Icons.EditIcon aria-hidden="true" className="h-4 w-4" />
                        </button>
                    </div>
                </>
            )}
        </div>
    );
};

